INSERT INTO authors (id, name, bio, created_at, updated_at)
SELECT id, name, bio, NOW(), NOW()
FROM author_seed seed
WHERE NOT EXISTS (
    SELECT 1
    FROM authors existing
    WHERE existing.id = seed.id OR existing.name = seed.name
);

