INSERT INTO books (id, author_id, title, isbn, published_year, created_at, updated_at)
SELECT seed.id, authors.id, seed.title, seed.isbn, seed.published_year, NOW(), NOW()
FROM book_seed seed
JOIN authors
    ON authors.name = seed.author_name
WHERE NOT EXISTS (
    SELECT 1
    FROM books existing
    WHERE existing.id = seed.id OR existing.isbn = seed.isbn
);
